    g_hash_table_destroy(ov->unprocessed_opts);

    ov->unprocessed_opts = NULL;

    if (ov->fake_id_opt) {

        g_free(ov->fake_id_opt->name);

        g_free(ov->fake_id_opt->str);

        g_free(ov->fake_id_opt);

    }

    ov->fake_id_opt = NULL;

}

