static void json_print_section_header(WriterContext *wctx)

{

    JSONContext *json = wctx->priv;

    AVBPrint buf;

    const struct section *section = wctx->section[wctx->level];

    const struct section *parent_section = wctx->level ?

        wctx->section[wctx->level-1] : NULL;



    if (wctx->level && wctx->nb_item[wctx->level-1])

        printf(",\n");



    if (section->flags & SECTION_FLAG_IS_WRAPPER) {

        printf("{\n");

        json->indent_level++;

    } else {

        av_bprint_init(&buf, 1, AV_BPRINT_SIZE_UNLIMITED);

        json_escape_str(&buf, section->name, wctx);

        JSON_INDENT();



        json->indent_level++;

        if (section->flags & SECTION_FLAG_IS_ARRAY) {

            printf("\"%s\": [\n", buf.str);

        } else if (!(parent_section->flags & SECTION_FLAG_IS_ARRAY)) {

            printf("\"%s\": {%s", buf.str, json->item_start_end);

        } else {

            printf("{%s", json->item_start_end);



            /* this is required so the parser can distinguish between packets and frames */

            if (parent_section->id == SECTION_ID_PACKETS_AND_FRAMES) {

                if (!json->compact)

                    JSON_INDENT();

                printf("\"type\": \"%s\"%s", section->name, json->item_sep);

            }

        }

        av_bprint_finalize(&buf, NULL);

    }

}

int kvm_init(int smp_cpus)
{
    KVMState *s;
    int ret;
    int i;
    if (smp_cpus > 1)
        return -EINVAL;
    s = qemu_mallocz(sizeof(KVMState));
    if (s == NULL)
        return -ENOMEM;
    for (i = 0; i < ARRAY_SIZE(s->slots); i++)
        s->slots[i].slot = i;
    s->vmfd = -1;
    s->fd = open("/dev/kvm", O_RDWR);
    if (s->fd == -1) {
        fprintf(stderr, "Could not access KVM kernel module: %m\n");
        ret = -errno;
        goto err;
    }
    ret = kvm_ioctl(s, KVM_GET_API_VERSION, 0);
    if (ret < KVM_API_VERSION) {
            ret = -EINVAL;
        fprintf(stderr, "kvm version too old\n");
        goto err;
    }
    if (ret > KVM_API_VERSION) {
        ret = -EINVAL;
        fprintf(stderr, "kvm version not supported\n");
        goto err;
    }
    s->vmfd = kvm_ioctl(s, KVM_CREATE_VM, 0);
    if (s->vmfd < 0)
        goto err;
    /* initially, KVM allocated its own memory and we had to jump through
     * hooks to make phys_ram_base point to this.  Modern versions of KVM
     * just use a user allocated buffer so we can use phys_ram_base
     * unmodified.  Make sure we have a sufficiently modern version of KVM.
     */
    ret = kvm_ioctl(s, KVM_CHECK_EXTENSION, KVM_CAP_USER_MEMORY);
    if (ret <= 0) {
        if (ret == 0)
            ret = -EINVAL;
        fprintf(stderr, "kvm does not support KVM_CAP_USER_MEMORY\n");
        goto err;
    }
    /* There was a nasty bug in < kvm-80 that prevents memory slots from being
     * destroyed properly.  Since we rely on this capability, refuse to work
     * with any kernel without this capability. */
    ret = kvm_ioctl(s, KVM_CHECK_EXTENSION,
                    KVM_CAP_DESTROY_MEMORY_REGION_WORKS);
    if (ret <= 0) {
        if (ret == 0)
            ret = -EINVAL;
        fprintf(stderr,
                "KVM kernel module broken (DESTROY_MEMORY_REGION)\n"
                "Please upgrade to at least kvm-81.\n");
        goto err;
    }
    ret = kvm_arch_init(s, smp_cpus);
    if (ret < 0)
        goto err;
    kvm_state = s;
    return 0;
err:
    if (s) {
        if (s->vmfd != -1)
            close(s->vmfd);
        if (s->fd != -1)
            close(s->fd);
    }
    qemu_free(s);
    return ret;
}

_eth_get_rss_ex_src_addr(const struct iovec *pkt, int pkt_frags,

                        size_t dsthdr_offset,

                        struct ip6_ext_hdr *ext_hdr,

                        struct in6_address *src_addr)

{

    size_t bytes_left = (ext_hdr->ip6r_len + 1) * 8 - sizeof(*ext_hdr);

    struct ip6_option_hdr opthdr;

    size_t opt_offset = dsthdr_offset + sizeof(*ext_hdr);



    while (bytes_left > sizeof(opthdr)) {

        size_t input_size = iov_size(pkt, pkt_frags);

        size_t bytes_read, optlen;



        if (input_size < opt_offset) {

            return false;

        }



        bytes_read = iov_to_buf(pkt, pkt_frags, opt_offset,

                                &opthdr, sizeof(opthdr));



        if (bytes_read != sizeof(opthdr)) {

            return false;

        }



        optlen = (opthdr.type == IP6_OPT_PAD1) ? 1

                                               : (opthdr.len + sizeof(opthdr));



        if (optlen > bytes_left) {

            return false;

        }



        if (opthdr.type == IP6_OPT_HOME) {

            size_t input_size = iov_size(pkt, pkt_frags);



            if (input_size < opt_offset + sizeof(opthdr)) {

                return false;

            }



            bytes_read = iov_to_buf(pkt, pkt_frags,

                                    opt_offset + sizeof(opthdr),

                                    src_addr, sizeof(*src_addr));



            return bytes_read == sizeof(src_addr);

        }



        opt_offset += optlen;

        bytes_left -= optlen;

    }



    return false;

}

static int64_t nfs_client_open(NFSClient *client, const char *filename,

                               int flags, Error **errp)

{

    int ret = -EINVAL, i;

    struct stat st;

    URI *uri;

    QueryParams *qp = NULL;

    char *file = NULL, *strp = NULL;



    uri = uri_parse(filename);

    if (!uri) {

        error_setg(errp, "Invalid URL specified");

        goto fail;

    }

    if (!uri->server) {

        error_setg(errp, "Invalid URL specified");

        goto fail;

    }

    strp = strrchr(uri->path, '/');

    if (strp == NULL) {

        error_setg(errp, "Invalid URL specified");

        goto fail;

    }

    file = g_strdup(strp);

    *strp = 0;



    client->context = nfs_init_context();

    if (client->context == NULL) {

        error_setg(errp, "Failed to init NFS context");

        goto fail;

    }



    qp = query_params_parse(uri->query);

    for (i = 0; i < qp->n; i++) {

        if (!qp->p[i].value) {

            error_setg(errp, "Value for NFS parameter expected: %s",

                       qp->p[i].name);

            goto fail;

        }

        if (!strncmp(qp->p[i].name, "uid", 3)) {

            nfs_set_uid(client->context, atoi(qp->p[i].value));

        } else if (!strncmp(qp->p[i].name, "gid", 3)) {

            nfs_set_gid(client->context, atoi(qp->p[i].value));

        } else if (!strncmp(qp->p[i].name, "tcp-syncnt", 10)) {

            nfs_set_tcp_syncnt(client->context, atoi(qp->p[i].value));

        } else {

            error_setg(errp, "Unknown NFS parameter name: %s",

                       qp->p[i].name);

            goto fail;

        }

    }



    ret = nfs_mount(client->context, uri->server, uri->path);

    if (ret < 0) {

        error_setg(errp, "Failed to mount nfs share: %s",

                   nfs_get_error(client->context));

        goto fail;

    }



    if (flags & O_CREAT) {

        ret = nfs_creat(client->context, file, 0600, &client->fh);

        if (ret < 0) {

            error_setg(errp, "Failed to create file: %s",

                       nfs_get_error(client->context));

            goto fail;

        }

    } else {

        ret = nfs_open(client->context, file, flags, &client->fh);

        if (ret < 0) {

            error_setg(errp, "Failed to open file : %s",

                       nfs_get_error(client->context));

            goto fail;

        }

    }



    ret = nfs_fstat(client->context, client->fh, &st);

    if (ret < 0) {

        error_setg(errp, "Failed to fstat file: %s",

                   nfs_get_error(client->context));

        goto fail;

    }



    ret = DIV_ROUND_UP(st.st_size, BDRV_SECTOR_SIZE);

    client->has_zero_init = S_ISREG(st.st_mode);

    goto out;

fail:

    nfs_client_close(client);

out:

    if (qp) {

        query_params_free(qp);

    }

    uri_free(uri);

    g_free(file);

    return ret;

}

static int nut_read_header(AVFormatContext * avf, AVFormatParameters * ap) {

    NUTContext * priv = avf->priv_data;

    AVIOContext * bc = avf->pb;

    nut_demuxer_opts_tt dopts = {

        .input = {

            .priv = bc,

            .seek = av_seek,

            .read = av_read,

            .eof = NULL,

            .file_pos = 0,

        },

        .alloc = { av_malloc, av_realloc, av_free },

        .read_index = 1,

        .cache_syncpoints = 1,

    };

    nut_context_tt * nut = priv->nut = nut_demuxer_init(&dopts);

    nut_stream_header_tt * s;

    int ret, i;



    if ((ret = nut_read_headers(nut, &s, NULL))) {

        av_log(avf, AV_LOG_ERROR, " NUT error: %s\n", nut_error(ret));


        return -1;




    priv->s = s;



    for (i = 0; s[i].type != -1 && i < 2; i++) {

        AVStream * st = avformat_new_stream(avf, NULL);

        int j;



        for (j = 0; j < s[i].fourcc_len && j < 8; j++) st->codec->codec_tag |= s[i].fourcc[j]<<(j*8);



        st->codec->has_b_frames = s[i].decode_delay;



        st->codec->extradata_size = s[i].codec_specific_len;

        if (st->codec->extradata_size) {

            st->codec->extradata = av_mallocz(st->codec->extradata_size);





            memcpy(st->codec->extradata, s[i].codec_specific, st->codec->extradata_size);




        avpriv_set_pts_info(avf->streams[i], 60, s[i].time_base.num, s[i].time_base.den);

        st->start_time = 0;

        st->duration = s[i].max_pts;



        st->codec->codec_id = ff_codec_get_id(nut_tags, st->codec->codec_tag);



        switch(s[i].type) {

        case NUT_AUDIO_CLASS:

            st->codec->codec_type = AVMEDIA_TYPE_AUDIO;

            if (st->codec->codec_id == CODEC_ID_NONE) st->codec->codec_id = ff_codec_get_id(ff_codec_wav_tags, st->codec->codec_tag);



            st->codec->channels = s[i].channel_count;

            st->codec->sample_rate = s[i].samplerate_num / s[i].samplerate_denom;

            break;

        case NUT_VIDEO_CLASS:

            st->codec->codec_type = AVMEDIA_TYPE_VIDEO;

            if (st->codec->codec_id == CODEC_ID_NONE) st->codec->codec_id = ff_codec_get_id(ff_codec_bmp_tags, st->codec->codec_tag);



            st->codec->width = s[i].width;

            st->codec->height = s[i].height;

            st->sample_aspect_ratio.num = s[i].sample_width;

            st->sample_aspect_ratio.den = s[i].sample_height;

            break;


        if (st->codec->codec_id == CODEC_ID_NONE) av_log(avf, AV_LOG_ERROR, "Unknown codec?!\n");




    return 0;

