                    if (callbacks->font_size)

                        callbacks->font_size(priv, size);

                } else if (sscanf(buf, "\\a%1[\\}]%n", sep, &len) > 0 ||

                           sscanf(buf, "\\a%2u%1[\\}]%n", &an, sep, &len) > 1 ||

                           sscanf(buf, "\\an%1[\\}]%n", sep, &len) > 0 ||

                           sscanf(buf, "\\an%1u%1[\\}]%n", &an, sep, &len) > 1) {

