static int decode_sequence_header_adv(VC1Context *v, GetBitContext *gb)

{

    v->res_rtm_flag = 1;

    v->level = get_bits(gb, 3);

    if(v->level >= 5)

    {

        av_log(v->s.avctx, AV_LOG_ERROR, "Reserved LEVEL %i\n",v->level);

    }

    v->chromaformat = get_bits(gb, 2);

    if (v->chromaformat != 1)

    {

        av_log(v->s.avctx, AV_LOG_ERROR,

               "Only 4:2:0 chroma format supported\n");

        return -1;

    }



    // (fps-2)/4 (->30)

    v->frmrtq_postproc = get_bits(gb, 3); //common

    // (bitrate-32kbps)/64kbps

    v->bitrtq_postproc = get_bits(gb, 5); //common

    v->postprocflag = get_bits(gb, 1); //common



    v->s.avctx->coded_width = (get_bits(gb, 12) + 1) << 1;

    v->s.avctx->coded_height = (get_bits(gb, 12) + 1) << 1;

    v->broadcast = get_bits1(gb);

    v->interlace = get_bits1(gb);

    if(v->interlace){

        av_log(v->s.avctx, AV_LOG_ERROR, "Interlaced mode not supported (yet)\n");

        return -1;

    }

    v->tfcntrflag = get_bits1(gb);

    v->finterpflag = get_bits1(gb);

    get_bits1(gb); // reserved

    v->psf = get_bits1(gb);

    if(v->psf) { //PsF, 6.1.13

        av_log(v->s.avctx, AV_LOG_ERROR, "Progressive Segmented Frame mode: not supported (yet)\n");

        return -1;

    }

    if(get_bits1(gb)) { //Display Info - decoding is not affected by it

        int w, h, ar = 0;

        av_log(v->s.avctx, AV_LOG_INFO, "Display extended info:\n");

        w = get_bits(gb, 14);

        h = get_bits(gb, 14);

        av_log(v->s.avctx, AV_LOG_INFO, "Display dimensions: %ix%i\n", w, h);

        //TODO: store aspect ratio in AVCodecContext

        if(get_bits1(gb))

            ar = get_bits(gb, 4);

        if(ar == 15) {

            w = get_bits(gb, 8);

            h = get_bits(gb, 8);

        }



        if(get_bits1(gb)){ //framerate stuff

            if(get_bits1(gb)) {

                get_bits(gb, 16);

            } else {

                get_bits(gb, 8);

                get_bits(gb, 4);

            }

        }



        if(get_bits1(gb)){

            v->color_prim = get_bits(gb, 8);

            v->transfer_char = get_bits(gb, 8);

            v->matrix_coef = get_bits(gb, 8);

        }

    }



    v->hrd_param_flag = get_bits1(gb);

    if(v->hrd_param_flag) {

        int i;

        v->hrd_num_leaky_buckets = get_bits(gb, 5);

        get_bits(gb, 4); //bitrate exponent

        get_bits(gb, 4); //buffer size exponent

        for(i = 0; i < v->hrd_num_leaky_buckets; i++) {

            get_bits(gb, 16); //hrd_rate[n]

            get_bits(gb, 16); //hrd_buffer[n]

        }

    }

    return 0;

}

int page_unprotect(target_ulong address, uintptr_t pc, void *puc)

{

    unsigned int prot;

    PageDesc *p;

    target_ulong host_start, host_end, addr;



    /* Technically this isn't safe inside a signal handler.  However we

       know this only ever happens in a synchronous SEGV handler, so in

       practice it seems to be ok.  */

    mmap_lock();



    p = page_find(address >> TARGET_PAGE_BITS);

    if (!p) {

        mmap_unlock();

        return 0;

    }



    /* if the page was really writable, then we change its

       protection back to writable */

    if ((p->flags & PAGE_WRITE_ORG) && !(p->flags & PAGE_WRITE)) {

        host_start = address & qemu_host_page_mask;

        host_end = host_start + qemu_host_page_size;



        prot = 0;

        for (addr = host_start ; addr < host_end ; addr += TARGET_PAGE_SIZE) {

            p = page_find(addr >> TARGET_PAGE_BITS);

            p->flags |= PAGE_WRITE;

            prot |= p->flags;



            /* and since the content will be modified, we must invalidate

               the corresponding translated code. */

            tb_invalidate_phys_page(addr, pc, puc);

#ifdef DEBUG_TB_CHECK

            tb_invalidate_check(addr);

#endif

        }

        mprotect((void *)g2h(host_start), qemu_host_page_size,

                 prot & PAGE_BITS);



        mmap_unlock();

        return 1;

    }

    mmap_unlock();

    return 0;

}

