static int protocol_version(VncState *vs, uint8_t *version, size_t len)

{

    char local[13];



    memcpy(local, version, 12);

    local[12] = 0;



    if (sscanf(local, "RFB %03d.%03d\n", &vs->major, &vs->minor) != 2) {

        VNC_DEBUG("Malformed protocol version %s\n", local);

        vnc_client_error(vs);

        return 0;

    }

    VNC_DEBUG("Client request protocol version %d.%d\n", vs->major, vs->minor);

    if (vs->major != 3 ||

        (vs->minor != 3 &&

         vs->minor != 4 &&

         vs->minor != 5 &&

         vs->minor != 7 &&

         vs->minor != 8)) {

        VNC_DEBUG("Unsupported client version\n");

        vnc_write_u32(vs, VNC_AUTH_INVALID);

        vnc_flush(vs);

        vnc_client_error(vs);

        return 0;

    }

    /* Some broken clients report v3.4 or v3.5, which spec requires to be treated

     * as equivalent to v3.3 by servers

     */

    if (vs->minor == 4 || vs->minor == 5)

        vs->minor = 3;



    if (vs->minor == 3) {

        if (vs->auth == VNC_AUTH_NONE) {

            VNC_DEBUG("Tell client auth none\n");

            vnc_write_u32(vs, vs->auth);

            vnc_flush(vs);

            start_client_init(vs);

       } else if (vs->auth == VNC_AUTH_VNC) {

            VNC_DEBUG("Tell client VNC auth\n");

            vnc_write_u32(vs, vs->auth);

            vnc_flush(vs);

            start_auth_vnc(vs);

       } else {

            VNC_DEBUG("Unsupported auth %d for protocol 3.3\n", vs->auth);

            vnc_write_u32(vs, VNC_AUTH_INVALID);

            vnc_flush(vs);

            vnc_client_error(vs);

       }

    } else {

        VNC_DEBUG("Telling client we support auth %d\n", vs->auth);

        vnc_write_u8(vs, 1); /* num auth */

        vnc_write_u8(vs, vs->auth);

        vnc_read_when(vs, protocol_client_auth, 1);

        vnc_flush(vs);

    }



    return 0;

}

qemu_irq *pxa2xx_pic_init(target_phys_addr_t base, CPUState *env)

{

    struct pxa2xx_pic_state_s *s;

    int iomemtype;

    qemu_irq *qi;



    s = (struct pxa2xx_pic_state_s *)

            qemu_mallocz(sizeof(struct pxa2xx_pic_state_s));

    if (!s)

        return NULL;



    s->cpu_env = env;

    s->base = base;



    s->int_pending[0] = 0;

    s->int_pending[1] = 0;

    s->int_enabled[0] = 0;

    s->int_enabled[1] = 0;

    s->is_fiq[0] = 0;

    s->is_fiq[1] = 0;



    qi = qemu_allocate_irqs(pxa2xx_pic_set_irq, s, PXA2XX_PIC_SRCS);



    /* Enable IC memory-mapped registers access.  */

    iomemtype = cpu_register_io_memory(0, pxa2xx_pic_readfn,

                    pxa2xx_pic_writefn, s);

    cpu_register_physical_memory(base, 0x000fffff, iomemtype);



    /* Enable IC coprocessor access.  */

    cpu_arm_set_cp_io(env, 6, pxa2xx_pic_cp_read, pxa2xx_pic_cp_write, s);



    register_savevm("pxa2xx_pic", 0, 0, pxa2xx_pic_save, pxa2xx_pic_load, s);



    return qi;

}

static av_always_inline void mpeg_motion_lowres(MpegEncContext *s,

                                                uint8_t *dest_y,

                                                uint8_t *dest_cb,

                                                uint8_t *dest_cr,

                                                int field_based,

                                                int bottom_field,

                                                int field_select,

                                                uint8_t **ref_picture,

                                                h264_chroma_mc_func *pix_op,

                                                int motion_x, int motion_y,

                                                int h, int mb_y)

{

    uint8_t *ptr_y, *ptr_cb, *ptr_cr;

    int mx, my, src_x, src_y, uvsrc_x, uvsrc_y, uvlinesize, linesize, sx, sy,

        uvsx, uvsy;

    const int lowres     = s->avctx->lowres;

    const int op_index   = FFMIN(lowres, 2);

    const int block_s    = 8>>lowres;

    const int s_mask     = (2 << lowres) - 1;

    const int h_edge_pos = s->h_edge_pos >> lowres;

    const int v_edge_pos = s->v_edge_pos >> lowres;

    linesize   = s->current_picture.f.linesize[0] << field_based;

    uvlinesize = s->current_picture.f.linesize[1] << field_based;



    // FIXME obviously not perfect but qpel will not work in lowres anyway

    if (s->quarter_sample) {

        motion_x /= 2;

        motion_y /= 2;

    }



    if (field_based) {

        motion_y += (bottom_field - field_select) * (1 << lowres - 1);

    }



    sx = motion_x & s_mask;

    sy = motion_y & s_mask;

    src_x = s->mb_x * 2 * block_s + (motion_x >> lowres + 1);

    src_y = (mb_y * 2 * block_s >> field_based) + (motion_y >> lowres + 1);



    if (s->out_format == FMT_H263) {

        uvsx    = ((motion_x >> 1) & s_mask) | (sx & 1);

        uvsy    = ((motion_y >> 1) & s_mask) | (sy & 1);

        uvsrc_x = src_x >> 1;

        uvsrc_y = src_y >> 1;

    } else if (s->out_format == FMT_H261) {

        // even chroma mv's are full pel in H261

        mx      = motion_x / 4;

        my      = motion_y / 4;

        uvsx    = (2 * mx) & s_mask;

        uvsy    = (2 * my) & s_mask;

        uvsrc_x = s->mb_x * block_s + (mx >> lowres);

        uvsrc_y =    mb_y * block_s + (my >> lowres);

    } else {

        mx      = motion_x / 2;

        my      = motion_y / 2;

        uvsx    = mx & s_mask;

        uvsy    = my & s_mask;

        uvsrc_x = s->mb_x * block_s                 + (mx >> lowres + 1);

        uvsrc_y =   (mb_y * block_s >> field_based) + (my >> lowres + 1);

    }



    ptr_y  = ref_picture[0] + src_y   * linesize   + src_x;

    ptr_cb = ref_picture[1] + uvsrc_y * uvlinesize + uvsrc_x;

    ptr_cr = ref_picture[2] + uvsrc_y * uvlinesize + uvsrc_x;



    if ((unsigned) src_x >  h_edge_pos - (!!sx) - 2 * block_s ||

        (unsigned) src_y > (v_edge_pos >> field_based) - (!!sy) - h) {

        s->dsp.emulated_edge_mc(s->edge_emu_buffer, ptr_y,

                                s->linesize, 17, 17 + field_based,

                                src_x, src_y << field_based, h_edge_pos,

                                v_edge_pos);

        ptr_y = s->edge_emu_buffer;

        if (!CONFIG_GRAY || !(s->flags & CODEC_FLAG_GRAY)) {

            uint8_t *uvbuf = s->edge_emu_buffer + 18 * s->linesize;

            s->dsp.emulated_edge_mc(uvbuf , ptr_cb, s->uvlinesize, 9,

                                    9 + field_based,

                                    uvsrc_x, uvsrc_y << field_based,

                                    h_edge_pos >> 1, v_edge_pos >> 1);

            s->dsp.emulated_edge_mc(uvbuf + 16, ptr_cr, s->uvlinesize, 9,

                                    9 + field_based,

                                    uvsrc_x, uvsrc_y << field_based,

                                    h_edge_pos >> 1, v_edge_pos >> 1);

            ptr_cb = uvbuf;

            ptr_cr = uvbuf + 16;

        }

    }



    // FIXME use this for field pix too instead of the obnoxious hack which changes picture.f.data

    if (bottom_field) {

        dest_y  += s->linesize;

        dest_cb += s->uvlinesize;

        dest_cr += s->uvlinesize;

    }



    if (field_select) {

        ptr_y   += s->linesize;

        ptr_cb  += s->uvlinesize;

        ptr_cr  += s->uvlinesize;

    }



    sx = (sx << 2) >> lowres;

    sy = (sy << 2) >> lowres;

    pix_op[lowres - 1](dest_y, ptr_y, linesize, h, sx, sy);



    if (!CONFIG_GRAY || !(s->flags & CODEC_FLAG_GRAY)) {

        uvsx = (uvsx << 2) >> lowres;

        uvsy = (uvsy << 2) >> lowres;

        pix_op[op_index](dest_cb, ptr_cb, uvlinesize, h >> s->chroma_y_shift,

                         uvsx, uvsy);

        pix_op[op_index](dest_cr, ptr_cr, uvlinesize, h >> s->chroma_y_shift,

                         uvsx, uvsy);

    }

    // FIXME h261 lowres loop filter

}

static void pci_ivshmem_realize(PCIDevice *dev, Error **errp)

{

    IVShmemState *s = IVSHMEM(dev);

    Error *err = NULL;

    uint8_t *pci_conf;

    uint8_t attr = PCI_BASE_ADDRESS_SPACE_MEMORY |

        PCI_BASE_ADDRESS_MEM_PREFETCH;



    if (!!s->server_chr + !!s->shmobj + !!s->hostmem != 1) {

        error_setg(errp,

                   "You must specify either 'shm', 'chardev' or 'x-memdev'");

        return;

    }



    if (s->hostmem) {

        MemoryRegion *mr;



        if (s->sizearg) {

            g_warning("size argument ignored with hostmem");

        }



        mr = host_memory_backend_get_memory(s->hostmem, &error_abort);

        s->ivshmem_size = memory_region_size(mr);

    } else if (s->sizearg == NULL) {

        s->ivshmem_size = 4 << 20; /* 4 MB default */

    } else {

        char *end;

        int64_t size = qemu_strtosz(s->sizearg, &end);

        if (size < 0 || *end != '\0' || !is_power_of_2(size)) {

            error_setg(errp, "Invalid size %s", s->sizearg);

            return;

        }

        s->ivshmem_size = size;

    }



    /* IRQFD requires MSI */

    if (ivshmem_has_feature(s, IVSHMEM_IOEVENTFD) &&

        !ivshmem_has_feature(s, IVSHMEM_MSI)) {

        error_setg(errp, "ioeventfd/irqfd requires MSI");

        return;

    }



    /* check that role is reasonable */

    if (s->role) {

        if (strncmp(s->role, "peer", 5) == 0) {

            s->role_val = IVSHMEM_PEER;

        } else if (strncmp(s->role, "master", 7) == 0) {

            s->role_val = IVSHMEM_MASTER;

        } else {

            error_setg(errp, "'role' must be 'peer' or 'master'");

            return;

        }

    } else {

        s->role_val = IVSHMEM_MASTER; /* default */

    }



    pci_conf = dev->config;

    pci_conf[PCI_COMMAND] = PCI_COMMAND_IO | PCI_COMMAND_MEMORY;



    /*

     * Note: we don't use INTx with IVSHMEM_MSI at all, so this is a

     * bald-faced lie then.  But it's a backwards compatible lie.

     */

    pci_config_set_interrupt_pin(pci_conf, 1);



    memory_region_init_io(&s->ivshmem_mmio, OBJECT(s), &ivshmem_mmio_ops, s,

                          "ivshmem-mmio", IVSHMEM_REG_BAR_SIZE);



    /* region for registers*/

    pci_register_bar(dev, 0, PCI_BASE_ADDRESS_SPACE_MEMORY,

                     &s->ivshmem_mmio);



    memory_region_init(&s->bar, OBJECT(s), "ivshmem-bar2-container", s->ivshmem_size);

    if (s->ivshmem_64bit) {

        attr |= PCI_BASE_ADDRESS_MEM_TYPE_64;

    }



    if (s->hostmem != NULL) {

        MemoryRegion *mr;



        IVSHMEM_DPRINTF("using hostmem\n");



        mr = host_memory_backend_get_memory(MEMORY_BACKEND(s->hostmem),

                                            &error_abort);

        vmstate_register_ram(mr, DEVICE(s));

        memory_region_add_subregion(&s->bar, 0, mr);

        pci_register_bar(PCI_DEVICE(s), 2, attr, &s->bar);

    } else if (s->server_chr != NULL) {

        /* FIXME do not rely on what chr drivers put into filename */

        if (strncmp(s->server_chr->filename, "unix:", 5)) {

            error_setg(errp, "chardev is not a unix client socket");

            return;

        }



        /* if we get a UNIX socket as the parameter we will talk

         * to the ivshmem server to receive the memory region */



        IVSHMEM_DPRINTF("using shared memory server (socket = %s)\n",

                        s->server_chr->filename);



        if (ivshmem_setup_interrupts(s) < 0) {

            error_setg(errp, "failed to initialize interrupts");

            return;

        }



        /* we allocate enough space for 16 peers and grow as needed */

        resize_peers(s, 16);

        s->vm_id = -1;



        pci_register_bar(dev, 2, attr, &s->bar);



        qemu_chr_add_handlers(s->server_chr, ivshmem_can_receive,

                              ivshmem_check_version, NULL, s);

    } else {

        /* just map the file immediately, we're not using a server */

        int fd;



        IVSHMEM_DPRINTF("using shm_open (shm object = %s)\n", s->shmobj);



        /* try opening with O_EXCL and if it succeeds zero the memory

         * by truncating to 0 */

        if ((fd = shm_open(s->shmobj, O_CREAT|O_RDWR|O_EXCL,

                        S_IRWXU|S_IRWXG|S_IRWXO)) > 0) {

           /* truncate file to length PCI device's memory */

            if (ftruncate(fd, s->ivshmem_size) != 0) {

                error_report("could not truncate shared file");

            }



        } else if ((fd = shm_open(s->shmobj, O_CREAT|O_RDWR,

                        S_IRWXU|S_IRWXG|S_IRWXO)) < 0) {

            error_setg(errp, "could not open shared file");

            return;

        }



        if (check_shm_size(s, fd, errp) == -1) {

            return;

        }



        create_shared_memory_BAR(s, fd, attr, &err);

        if (err) {

            error_propagate(errp, err);

            return;

        }

    }



    fifo8_create(&s->incoming_fifo, sizeof(int64_t));



    if (s->role_val == IVSHMEM_PEER) {

        error_setg(&s->migration_blocker,

                   "Migration is disabled when using feature 'peer mode' in device 'ivshmem'");

        migrate_add_blocker(s->migration_blocker);

    }

}

