int print_insn_lm32(bfd_vma memaddr, struct disassemble_info *info)

{

    fprintf_function fprintf_fn = info->fprintf_func;

    void *stream = info->stream;

    int rc;

    uint8_t insn[4];

    const Lm32OpcodeInfo *opc_info;

    uint32_t op;

    const char *args_fmt;



    rc = info->read_memory_func(memaddr, insn, 4, info);

    if (rc != 0) {

        info->memory_error_func(rc, memaddr, info);

        return -1;

    }



    fprintf_fn(stream, "%02x %02x %02x %02x    ",

            insn[0], insn[1], insn[2], insn[3]);



    op = bfd_getb32(insn);

    opc_info = find_opcode_info(op);

    if (opc_info) {

        fprintf_fn(stream, "%-8s ", opc_info->name);

        args_fmt = opc_info->args_fmt;

        while (args_fmt && *args_fmt) {

            if (*args_fmt == '%') {

                switch (*(++args_fmt)) {

                case '0': {

                    uint8_t r0;

                    const char *r0_name;

                    r0 = (op >> 21) & 0x1f;

                    r0_name = find_reg_info(r0)->name;

                    fprintf_fn(stream, "%s", r0_name);

                    break;

                }

                case '1': {

                    uint8_t r1;

                    const char *r1_name;

                    r1 = (op >> 16) & 0x1f;

                    r1_name = find_reg_info(r1)->name;

                    fprintf_fn(stream, "%s", r1_name);

                    break;

                }

                case '2': {

                    uint8_t r2;

                    const char *r2_name;

                    r2 = (op >> 11) & 0x1f;

                    r2_name = find_reg_info(r2)->name;

                    fprintf_fn(stream, "%s", r2_name);

                    break;

                }

                case 'c': {

                    uint8_t csr;

                    const char *csr_name;

                    csr = (op >> 21) & 0x1f;

                    csr_name = find_csr_info(csr)->name;

                    if (csr_name) {

                        fprintf_fn(stream, "%s", csr_name);

                    } else {

                        fprintf_fn(stream, "0x%x", csr);

                    }

                    break;

                }

                case 'u': {

                    uint16_t u16;

                    u16 = op & 0xffff;

                    fprintf_fn(stream, "0x%x", u16);

                    break;

                }

                case 's': {

                    int16_t s16;

                    s16 = (int16_t)(op & 0xffff);

                    fprintf_fn(stream, "%d", s16);

                    break;

                }

                case 'r': {

                    uint32_t rela;

                    rela = memaddr + (((int16_t)(op & 0xffff)) << 2);

                    fprintf_fn(stream, "%x", rela);

                    break;

                }

                case 'R': {

                    uint32_t rela;

                    int32_t imm26;

                    imm26 = (int32_t)((op & 0x3ffffff) << 6) >> 4;

                    rela = memaddr + imm26;

                    fprintf_fn(stream, "%x", rela);

                    break;

                }

                case 'h': {

                    uint8_t u5;

                    u5 = (op & 0x1f);

                    fprintf_fn(stream, "%d", u5);

                    break;

                }

                default:

                    break;

                }

            } else {

                fprintf_fn(stream, "%c", *args_fmt);

            }

            args_fmt++;

        }

    } else {

        fprintf_fn(stream, ".word 0x%x", op);

    }



    return 4;

}

static int mp_decode_frame(MPADecodeContext *s, OUT_INT **samples,

                           const uint8_t *buf, int buf_size)

{

    int i, nb_frames, ch, ret;

    OUT_INT *samples_ptr;



    init_get_bits(&s->gb, buf + HEADER_SIZE, (buf_size - HEADER_SIZE) * 8);



    /* skip error protection field */

    if (s->error_protection)

        skip_bits(&s->gb, 16);



    switch(s->layer) {

    case 1:

        s->avctx->frame_size = 384;

        nb_frames = mp_decode_layer1(s);

        break;

    case 2:

        s->avctx->frame_size = 1152;

        nb_frames = mp_decode_layer2(s);

        break;

    case 3:

        s->avctx->frame_size = s->lsf ? 576 : 1152;

    default:

        nb_frames = mp_decode_layer3(s);



        if (nb_frames < 0)

            return nb_frames;



        s->last_buf_size=0;

        if (s->in_gb.buffer) {

            align_get_bits(&s->gb);

            i = get_bits_left(&s->gb)>>3;

            if (i >= 0 && i <= BACKSTEP_SIZE) {

                memmove(s->last_buf, s->gb.buffer + (get_bits_count(&s->gb)>>3), i);

                s->last_buf_size=i;

            } else

                av_log(s->avctx, AV_LOG_ERROR, "invalid old backstep %d\n", i);

            s->gb           = s->in_gb;

            s->in_gb.buffer = NULL;

        }



        align_get_bits(&s->gb);

        assert((get_bits_count(&s->gb) & 7) == 0);

        i = get_bits_left(&s->gb) >> 3;



        if (i < 0 || i > BACKSTEP_SIZE || nb_frames < 0) {

            if (i < 0)

                av_log(s->avctx, AV_LOG_ERROR, "invalid new backstep %d\n", i);

            i = FFMIN(BACKSTEP_SIZE, buf_size - HEADER_SIZE);

        }

        assert(i <= buf_size - HEADER_SIZE && i >= 0);

        memcpy(s->last_buf + s->last_buf_size, s->gb.buffer + buf_size - HEADER_SIZE - i, i);

        s->last_buf_size += i;

    }



    /* get output buffer */

    if (!samples) {

        av_assert0(s->frame != NULL);

        s->frame->nb_samples = s->avctx->frame_size;

        if ((ret = ff_get_buffer(s->avctx, s->frame, 0)) < 0) {

            av_log(s->avctx, AV_LOG_ERROR, "get_buffer() failed\n");

            return ret;

        }

        samples = (OUT_INT **)s->frame->extended_data;

    }



    /* apply the synthesis filter */

    for (ch = 0; ch < s->nb_channels; ch++) {

        int sample_stride;

        if (s->avctx->sample_fmt == OUT_FMT_P) {

            samples_ptr   = samples[ch];

            sample_stride = 1;

        } else {

            samples_ptr   = samples[0] + ch;

            sample_stride = s->nb_channels;

        }

        for (i = 0; i < nb_frames; i++) {

            RENAME(ff_mpa_synth_filter)(&s->mpadsp, s->synth_buf[ch],

                                        &(s->synth_buf_offset[ch]),

                                        RENAME(ff_mpa_synth_window),

                                        &s->dither_state, samples_ptr,

                                        sample_stride, s->sb_samples[ch][i]);

            samples_ptr += 32 * sample_stride;

        }

    }



    return nb_frames * 32 * sizeof(OUT_INT) * s->nb_channels;

}

void rgb15tobgr15(const uint8_t *src, uint8_t *dst, unsigned int src_size)

{

	unsigned i;

	unsigned num_pixels = src_size >> 1;



	for(i=0; i<num_pixels; i++)

	{

	    unsigned b,g,r;

	    register uint16_t rgb;

	    rgb = src[2*i];

	    r = rgb&0x1F;

	    g = (rgb&0x3E0)>>5;

	    b = (rgb&0x7C00)>>10;

	    dst[2*i] = (b&0x1F) | ((g&0x1F)<<5) | ((r&0x1F)<<10);

	}

}

