    LOCAL_ALIGNED_32(uint8_t, dst0, [32 * 32 * 2]);

    LOCAL_ALIGNED_32(uint8_t, dst1, [32 * 32 * 2]);



    for (i = 2; i <= 5; i++) {

        int block_size = 1 << i;

