static int hdev_open(BlockDriverState *bs, QDict *options, int flags,

                     Error **errp)

{

    BDRVRawState *s = bs->opaque;

    Error *local_err = NULL;

    int ret;



#if defined(__APPLE__) && defined(__MACH__)







    const char *filename = qdict_get_str(options, "filename");

    char bsd_path[MAXPATHLEN] = "";

    bool error_occurred = false;



    /* If using a real cdrom */

    if (strcmp(filename, "/dev/cdrom") == 0) {

        char *mediaType = NULL;

        kern_return_t ret_val;

        io_iterator_t mediaIterator = 0;



        mediaType = FindEjectableOpticalMedia(&mediaIterator);

        if (mediaType == NULL) {

            error_setg(errp, "Please make sure your CD/DVD is in the optical"

                       " drive");

            error_occurred = true;

            goto hdev_open_Mac_error;

        }



        ret_val = GetBSDPath(mediaIterator, bsd_path, sizeof(bsd_path), flags);

        if (ret_val != KERN_SUCCESS) {

            error_setg(errp, "Could not get BSD path for optical drive");

            error_occurred = true;

            goto hdev_open_Mac_error;

        }



        /* If a real optical drive was not found */

        if (bsd_path[0] == '\0') {

            error_setg(errp, "Failed to obtain bsd path for optical drive");

            error_occurred = true;

            goto hdev_open_Mac_error;

        }



        /* If using a cdrom disc and finding a partition on the disc failed */

        if (strncmp(mediaType, kIOCDMediaClass, 9) == 0 &&

            setup_cdrom(bsd_path, errp) == false) {

            print_unmounting_directions(bsd_path);

            error_occurred = true;

            goto hdev_open_Mac_error;

        }



        qdict_put(options, "filename", qstring_from_str(bsd_path));



hdev_open_Mac_error:

        g_free(mediaType);

        if (mediaIterator) {

            IOObjectRelease(mediaIterator);

        }

        if (error_occurred) {

            return -ENOENT;

        }

    }

#endif /* defined(__APPLE__) && defined(__MACH__) */



    s->type = FTYPE_FILE;



    ret = raw_open_common(bs, options, flags, 0, &local_err);

    if (ret < 0) {

        error_propagate(errp, local_err);

#if defined(__APPLE__) && defined(__MACH__)

        if (*bsd_path) {

            filename = bsd_path;

        }

        /* if a physical device experienced an error while being opened */

        if (strncmp(filename, "/dev/", 5) == 0) {

            print_unmounting_directions(filename);

        }

#endif /* defined(__APPLE__) && defined(__MACH__) */

        return ret;

    }



    /* Since this does ioctl the device must be already opened */

    bs->sg = hdev_is_sg(bs);



    if (flags & BDRV_O_RDWR) {

        ret = check_hdev_writable(s);

        if (ret < 0) {

            raw_close(bs);

            error_setg_errno(errp, -ret, "The device is not writable");

            return ret;

        }

    }



    return ret;

}

int LLVMFuzzerTestOneInput(const uint8_t *data, size_t size) {

    const uint64_t fuzz_tag = FUZZ_TAG;

    FuzzDataBuffer buffer;

    const uint8_t *last = data;

    const uint8_t *end = data + size;

    uint32_t it = 0;



    if (!c)

        c = AVCodecInitialize(FFMPEG_CODEC);  // Done once.



    AVCodecContext* ctx = avcodec_alloc_context3(NULL);

    if (!ctx)

        error("Failed memory allocation");



    ctx->max_pixels = 4096 * 4096; //To reduce false positive OOM and hangs



    int res = avcodec_open2(ctx, c, NULL);

    if (res < 0)

        return res;



    FDBCreate(&buffer);

    int got_frame;

    AVFrame *frame = av_frame_alloc();

    if (!frame)

        error("Failed memory allocation");



    // Read very simple container

    AVPacket avpkt;

    while (data < end && it < maxiteration) {

        // Search for the TAG

        while (data + sizeof(fuzz_tag) < end) {

            if (data[0] == (fuzz_tag & 0xFF) && *(const uint64_t *)(data) == fuzz_tag)

                break;

            data++;

        }

        if (data + sizeof(fuzz_tag) > end)

            data = end;



        FDBPrepare(&buffer, &avpkt, last, data - last);

        data += sizeof(fuzz_tag);

        last = data;



        // Iterate through all data

        while (avpkt.size > 0 && it++ < maxiteration) {

            av_frame_unref(frame);

            int ret = decode_handler(ctx, frame, &got_frame, &avpkt);



            if (it > 20)

                ctx->error_concealment = 0;



            if (ret <= 0 || ret > avpkt.size)

               break;



            avpkt.data += ret;

            avpkt.size -= ret;

        }

    }



    av_init_packet(&avpkt);

    avpkt.data = NULL;

    avpkt.size = 0;



    do {

        got_frame = 0;

        decode_handler(ctx, frame, &got_frame, &avpkt);

    } while (got_frame == 1 && it++ < maxiteration);



    av_frame_free(&frame);

    avcodec_free_context(&ctx);

    av_freep(&ctx);

    FDBDesroy(&buffer);

    return 0;

}

